// shadcn
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";

// constants
const items = [
  {
    id: 1,
    image: "https://cdn.uiable.com/block/g1.jpg",
    alt: "Gallery image 1",
  },
  {
    id: 2,
    image: "https://cdn.uiable.com/block/g2.jpg",
    alt: "Gallery image 2",
  },
  {
    id: 3,
    image: "https://cdn.uiable.com/block/g3.jpg",
    alt: "Gallery image 3",
  },
  {
    id: 4,
    image: "https://cdn.uiable.com/block/g4.jpg",
    alt: "Gallery image 4",
  },
  {
    id: 5,
    image: "https://cdn.uiable.com/block/g5.jpg",
    alt: "Gallery image 5",
  },
  {
    id: 6,
    image: "https://cdn.uiable.com/block/g6.jpg",
    alt: "Gallery image 6",
  },
];

//  ------------------------------ | GALLERY 5 | ------------------------------  //

export default function Gallery5() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-16 lg:px-20">
        {/* Header */}
        <div className="text-center mb-14">
          <h2 className="text-foreground">Gallery</h2>
        </div>

        {/* Carousel — arrows outside via px padding on wrapper */}
        <Carousel
          opts={{ align: "start", loop: true }}
          className="w-full px-12"
        >
          <CarouselContent className="-ml-4">
            {items.map((item) => (
              <CarouselItem
                key={item.id}
                className="basis-full sm:basis-1/2 md:basis-1/4 pl-4"
              >
                <div className="overflow-hidden rounded-2xl aspect-square">
                  <img
                    src={item.image}
                    alt={item.alt}
                    className="w-full h-full object-cover"
                  />
                </div>
              </CarouselItem>
            ))}
          </CarouselContent>
          <CarouselPrevious />
          <CarouselNext />
        </Carousel>
      </div>
    </section>
  );
}
